local roomname = matches[2] local foundrooms = searchRoom(roomname, true, true)
if table.is_empty(foundrooms) then selectCaptureGroup(2) setLink(function() end, "No matches found!") elseif table.size(foundrooms) == 1 then for id, name in pairs(foundrooms) do selectCaptureGroup(2) setLink(function() centerview(id) end, "Click to center map on room.") end else selectCaptureGroup(2)
setLink(function() for id, name in spairs(foundrooms) do local zone = getRoomUserData(k, "zone"){zone} echoLink(f"Room ID: {id}, zone: {zone}\n", function() centerview(id) end, "Click to center map on room.",true) end end, "Click to display rooms with matching name.") end

Alias.script:
--syntax: resetgates
weaving = weaving or {}
if weaving.name then table.save(f"{getMudletHomeDir()}/{weaving.name}_gatecodes.lua", {}) cecho("Gate codes reset!\n") else cecho("<red>Error! Character name not known.\n") end

--syntax: viewcodes
weaving = weaving or {} gatecodes = {}
if weaving.name then if io.exists(f"{getMudletHomeDir()}/{weaving.name}_gatecodes.lua") then table.load(f"{getMudletHomeDir()}/{weaving.name}_gatecodes.lua", gatecodes) end if table.is_empty(gatecodes) then cecho("No gatecodes known!
") else for loc, code in pairs(gatecodes) do cecho(f"Location: {loc}, code: {code}
") end end else cecho("<red>Error! Character name not known.
") end

